import pandas as pd, numpy as np, math

# 使用已暂存的数据，不重查实体、不覆盖最终输出变量；仅创建本空间分析环节变量
spatial_agent_notes = []

def _df_info(name, df):
    return {"name": name, "rows": int(len(df)), "cols": list(df.columns)}

def _first_numeric_by_keywords(df, keywords, exclude=()):
    if df is None or len(df) == 0:
        return None, None
    for col in df.columns:
        cl = str(col).lower()
        if all(k in cl for k in keywords) and not any(e in cl for e in exclude):
            s = pd.to_numeric(df[col], errors="coerce").dropna()
            if len(s):
                return float(s.iloc[0]), col
    return None, None

def _first_numeric_any(df, candidates):
    if df is None or len(df) == 0:
        return None, None
    lower_map = {str(c).lower(): c for c in df.columns}
    for cand in candidates:
        if cand.lower() in lower_map:
            col = lower_map[cand.lower()]
            s = pd.to_numeric(df[col], errors="coerce").dropna()
            if len(s):
                return float(s.iloc[0]), col
    return None, None

def _angular_diff(a, b):
    if a is None or b is None or pd.isna(a) or pd.isna(b):
        return None
    return abs((float(a) - float(b) + 180.0) % 360.0 - 180.0)

# 1) 距离与方位：优先复用已暂存的企业-站点空间结果
spatial_agent_company_station_df_summary = _df_info("daq_company_station_spatial_df", daq_company_station_spatial_df)

spatial_agent_company_to_station_distance_km, spatial_agent_distance_source_col = _first_numeric_by_keywords(
    daq_company_station_spatial_df, ["distance"], exclude=("m",)
)
if spatial_agent_company_to_station_distance_km is None:
    v, c = _first_numeric_by_keywords(daq_company_station_spatial_df, ["distance"])
    if v is not None:
        spatial_agent_company_to_station_distance_km = float(v) / 1000.0 if v > 100 else float(v)
        spatial_agent_distance_source_col = c

spatial_agent_company_to_station_bearing_deg, spatial_agent_bearing_source_col = _first_numeric_by_keywords(
    daq_company_station_spatial_df, ["bearing"]
)
if spatial_agent_company_to_station_bearing_deg is None:
    spatial_agent_company_to_station_bearing_deg, spatial_agent_bearing_source_col = _first_numeric_by_keywords(
        daq_company_station_spatial_df, ["azimuth"]
    )

if spatial_agent_company_to_station_distance_km is None:
    spatial_agent_notes.append("已暂存空间结果中未找到可用距离值；未存储静默空值。")
