)
if spatial_agent_company_flue_gas_1400_value is None:
    spatial_agent_notes.append("企业2427在2025-07-10 14:00的烟气量暂存结果为空或缺少可识别字段。")
if spatial_agent_station_pm25_1400_value is None:
    spatial_agent_notes.append("站点48在2025-07-10 14:00的PM2.5暂存结果为空或缺少可识别字段。")

# 3) 气象传输背景：优先使用站点周边10公里网格风；并保留区/市级气象作为补充
wind_df = daq_station_grid_wind_10km_1400_df.copy()
spatial_agent_grid_wind_rows = int(len(wind_df))
spatial_agent_grid_wind_summary = {}

if spatial_agent_grid_wind_rows > 0:
    wd_col = next((c for c in wind_df.columns if str(c).lower() in ["wind_degree", "avg_wind_degree", "mean_wind_degree"]), None)
    ws_col = next((c for c in wind_df.columns if str(c).lower() in ["wind_speed", "avg_wind_speed", "mean_wind_speed"]), None)
    dir_col = next((c for c in wind_df.columns if "wind_direction" in str(c).lower()), None)

    wind_degrees = pd.to_numeric(wind_df[wd_col], errors="coerce").dropna() if wd_col else pd.Series(dtype=float)
    wind_speeds = pd.to_numeric(wind_df[ws_col], errors="coerce").dropna() if ws_col else pd.Series(dtype=float)

    if len(wind_degrees):
        rad = np.deg2rad(wind_degrees.to_numpy())
        mean_sin, mean_cos = np.sin(rad).mean(), np.cos(rad).mean()
        spatial_agent_grid_mean_wind_from_deg = float((np.rad2deg(np.arctan2(mean_sin, mean_cos)) + 360.0) % 360.0)
        spatial_agent_grid_mean_transport_to_deg = float((spatial_agent_grid_mean_wind_from_deg + 180.0) % 360.0)
        spatial_agent_grid_transport_alignment_diff_deg = _angular_diff(
            spatial_agent_grid_mean_transport_to_deg, spatial_agent_company_to_station_bearing_deg
        )
        spatial_agent_grid_wind_summary.update({
            "wind_degree_count": int(len(wind_degrees)),
            "mean_wind_from_deg_vector": spatial_agent_grid_mean_wind_from_deg,
            "mean_transport_to_deg": spatial_agent_grid_mean_transport_to_deg,
            "transport_vs_company_to_station_abs_diff_deg": spatial_agent_grid_transport_alignment_diff_deg
        })
    else:
        spatial_agent_grid_mean_wind_from_deg = None
        spatial_agent_grid_mean_transport_to_deg = None
        spatial_agent_grid_transport_alignment_diff_deg = None
        spatial_agent_notes.append("站点周边10公里网格风场缺少可用风向角。")

    if len(wind_speeds):
        spatial_agent_grid_mean_wind_speed = float(wind_speeds.mean())
        spatial_agent_grid_wind_speed_min = float(wind_speeds.min())
        spatial_agent_grid_wind_speed_max = float(wind_speeds.max())
        spatial_agent_grid_wind_summary.update({
            "wind_speed_count": int(len(wind_speeds)),
            "mean_wind_speed": spatial_agent_grid_mean_wind_speed,
            "min_wind_speed": spatial_agent_grid_wind_speed_min,
            "max_wind_speed": spatial_agent_grid_wind_speed_max
        })
    else:
        spatial_agent_grid_mean_wind_speed = None
        spatial_agent_notes.append("站点周边10公里网格风场缺少可用风速。")

    if dir_col:
        spatial_agent_grid_wind_direction_counts = wind_df[dir_col].dropna().astype(str).value_counts().head(5).to_dict()
        spatial_agent_grid_wind_summary["top_wind_direction_labels"] = spatial_agent_grid_wind_direction_counts
    else:
        spatial_agent_grid_wind_direction_counts = {}
else:
    spatial_agent_grid_mean_wind_from_deg = None
    spatial_agent_grid_mean_transport_to_deg = None
    spatial_agent_grid_transport_alignment_diff_deg = None
    spatial_agent_grid_mean_wind_speed = None
    spatial_agent_grid_wind_direction_counts = {}
    spatial_agent_notes.append("站点周边10公里网格风场暂存结果为空。")

# 区/市级天气摘要（如已获取）
def _weather_summary(df, prefix):
    out = {"rows": int(len(df))}
    if len(df):
        for key in ["wind_degree", "wind_speed", "humidity", "temperature"]:
            col = next((c for c in df.columns if str(c).lower() == key), None)
            if col:
                vals = pd.to_numeric(df[col], errors="coerce").dropna()
                if len(vals):
                    out[key] = float(vals.iloc[0])
        dcol = next((c for c in df.columns if "wind_direction" in str(c).lower()), None)
        if dcol and df[dcol].notna().any():
            out["wind_direction"] = str(df[dcol].dropna().iloc[0])
    return out

spatial_agent_station_district_weather_summary = _weather_summary(daq_station_district_weather_1400_df, "district")
